    UniqueHandle hProcess(OpenProcess(PROCESS_VM_OPERATION | PROCESS_VM_READ | PROCESS_VM_WRITE, FALSE, processID));
    if (!hProcess) {
        g_logger.Log("Failed to open target process.");
        return false;
    }

