// Функция поиска и применения патча
bool patchSignatureInProcessMemory(HANDLE hProcess, const std::vector<BYTE>& signature, const std::vector<BYTE>& patchBytes, bool replaceAll = false) {
    bool result = false;
    MEMORY_BASIC_INFORMATION mbi{};
    BYTE* addr = nullptr;

    while (VirtualQueryEx(hProcess, addr, &mbi, sizeof(mbi))) {
        if (mbi.State == MEM_COMMIT && (mbi.Protect == PAGE_READWRITE || mbi.Protect == PAGE_EXECUTE_READWRITE)) {
            std::vector<BYTE> buffer(mbi.RegionSize);
            SIZE_T bytesRead;
            if (ReadProcessMemory(hProcess, mbi.BaseAddress, buffer.data(), mbi.RegionSize, &bytesRead)) {
                for (size_t i = 0; i <= bytesRead - signature.size(); ++i) {
                    if (memcmp(buffer.data() + i, signature.data(), signature.size()) == 0) {
                        if (applyPatch(hProcess, static_cast<BYTE*>(mbi.BaseAddress) + i, patchBytes)) {
                            result = true;
                            if (!replaceAll) return true;
                        }
